script.code:
def aff = primaryAffiliation != null ? basic.stringify(primaryAffiliation).trim().toLowerCase() : '';
if (aff == '') return null;
if (aff == 'faculty') return 'DOCEN';
if (aff == 'researcher') return 'INVESTI';
if (aff == 'staff' || aff == 'employee') return 'ADMINIST';
if (aff == 'alum') return 'ALUMNI';
if (aff == 'affiliate') return 'VISITA';
if (aff != 'student') return null;
def level = studyLevel != null ? basic.stringify(studyLevel).trim().toLowerCase() : '';
if (level == 'maestria' || level == 'doctorado' || level == 'segunda-especialidad' || level == 'especializacion' || level.contains('posgrado')) return 'POSGRADO';
if (level == 'pregrado') return 'PREGRADO';
def cycles = (studentCycle instanceof Collection) ? studentCycle : (studentCycle != null ? [studentCycle] : []);
def maxCycle = cycles.collect { it?.toString()?.trim()?.isInteger() ? it.toString().trim().toInteger() : -1 }.max();
if (maxCycle != null && maxCycle >= 7) return 'POSGRADO';
if (!cycles.isEmpty()) return 'PREGRADO';
def hasPosgradoRole = focus?.roleMembershipRef?.any { it?.oid == 'a1b2c3d4-e5f6-7890-abcd-ef1234567802' };
return hasPosgradoRole ? 'POSGRADO' : 'PREGRADO';
